#!/usr/bin/env bash
set -e

# ════════════════════════════════════════════════════════════════
#  WINBOX WEB - Unified Installer & Launcher
#  Self-extracting: creates full project then starts web UI
#
#  Usage:
#    chmod +x winbox-web.sh && ./winbox-web.sh
# ════════════════════════════════════════════════════════════════

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_DIR="${SCRIPT_DIR}/winbox-web"
VENV_DIR="${PROJECT_DIR}/venv"

R='\033[1;31m'; G='\033[1;32m'; Y='\033[1;33m'
B='\033[1;34m'; C='\033[1;36m'; W='\033[0m'

_ok()   { echo -e "${G}✔${W} $1"; }
_warn() { echo -e "${Y}⚠${W} $1"; }
_info() { echo -e "${B}ℹ${W} $1"; }
_fail() { echo -e "${R}✘${W} $1"; }

extract_file() {
    local _name="$1" _data="$2" _dest="$3"
    mkdir -p "$(dirname "$_dest")"
    printf '%s' "$_data" | base64 -d | gunzip > "$_dest"
    _ok "Extracted: $_name"
}

# requirements.txt
DATA_REQ="H4sIAHTMYGoC/0tLLC5JLMi0szXQMzQw0TPgKi3LTM4vyosGCuelJBalxIKkjEAy5alJxfnJ2aklxXa2hkZAgYLKkoz8PN3c0pySzILEohKQSgM9My4Ae0h91lQAAAA="

# backend/main.py  
DATA_BACKEND=""

# frontend/index.html
DATA_FRONTEND=""

# scripts/winbox.sh
DATA_WINBOX=""

do_install() {
    echo ""
    echo -e "${C}══════════════════════════════════════════════════════════════${W}"
    echo -e "${C}              WinBox Web - Installation${W}"
    echo -e "${C}══════════════════════════════════════════════════════════════${W}"
    echo ""

    local _pkg=""
    if command -v apt-get &>/dev/null; then _pkg="apt-get"
    elif command -v yum &>/dev/null; then _pkg="yum"
    elif command -v pacman &>/dev/null; then _pkg="pacman"
    fi

    _info "Installing system dependencies..."
    if [[ -n "$_pkg" ]]; then
        if [[ "$_pkg" == "apt-get" ]]; then
            sudo apt-get update -qq >/dev/null 2>&1 || true
            sudo apt-get install -y -qq python3 python3-pip python3-venv \
                qemu-system-x86 qemu-utils curl wget git 2>/dev/null || true
        elif [[ "$_pkg" == "yum" ]]; then
            sudo yum install -y python3 python3-pip qemu-kvm qemu-img curl wget git 2>/dev/null || true
        elif [[ "$_pkg" == "pacman" ]]; then
            sudo pacman -S --noconfirm python python-pip qemu-full curl wget git 2>/dev/null || true
        fi
    fi

    if ! command -v python3 &>/dev/null; then
        _fail "python3 not found. Please install python3 first."
        exit 1
    fi

    _info "Creating project structure..."
    mkdir -p "${PROJECT_DIR}/backend"
    mkdir -p "${PROJECT_DIR}/frontend"
    mkdir -p "${PROJECT_DIR}/novnc"
    mkdir -p "${PROJECT_DIR}/scripts"
    mkdir -p "${PROJECT_DIR}/data"
    mkdir -p "${PROJECT_DIR}/logs"

    extract_file "requirements.txt" "$DATA_REQ" "${PROJECT_DIR}/backend/requirements.txt"
    extract_file "main.py" "$DATA_BACKEND" "${PROJECT_DIR}/backend/main.py"
    extract_file "index.html" "$DATA_FRONTEND" "${PROJECT_DIR}/frontend/index.html"
    extract_file "winbox.sh" "$DATA_WINBOX" "${PROJECT_DIR}/scripts/winbox.sh"
    chmod +x "${PROJECT_DIR}/scripts/winbox.sh"

    _info "Downloading noVNC..."
    local _novnc_ok=0
    if command -v curl &>/dev/null; then
        if curl -fsSL -o /tmp/novnc.tar.gz \
            "https://github.com/novnc/noVNC/archive/refs/tags/v1.4.0.tar.gz" 2>/dev/null; then
            _novnc_ok=1
        fi
    elif command -v wget &>/dev/null; then
        if wget -q -O /tmp/novnc.tar.gz \
            "https://github.com/novnc/noVNC/archive/refs/tags/v1.4.0.tar.gz" 2>/dev/null; then
            _novnc_ok=1
        fi
    fi

    if [[ "$_novnc_ok" == "1" ]] && [[ -f /tmp/novnc.tar.gz ]]; then
        tar -xzf /tmp/novnc.tar.gz -C /tmp/ 2>/dev/null || true
        if [[ -d /tmp/noVNC-1.4.0 ]]; then
            cp -r /tmp/noVNC-1.4.0/* "${PROJECT_DIR}/novnc/" 2>/dev/null || true
            rm -rf /tmp/novnc.tar.gz /tmp/noVNC-1.4.0
            _ok "noVNC downloaded"
        fi
    else
        _warn "Could not download noVNC - creating placeholder"
        cat > "${PROJECT_DIR}/novnc/vnc.html" << 'HTMLEOF'
<!DOCTYPE html>
<html><head><title>noVNC</title></head>
<body><h1>noVNC</h1><p>Install noVNC: git clone https://github.com/novnc/noVNC.git</p></body>
</html>
HTMLEOF
    fi

    _info "Creating Python virtual environment..."
    python3 -m venv "$VENV_DIR" 2>/dev/null || {
        _fail "Failed to create venv. Install python3-venv package."
        exit 1
    }

    _info "Installing Python packages..."
    "$VENV_DIR/bin/pip" install --upgrade pip -q
    "$VENV_DIR/bin/pip" install -r "${PROJECT_DIR}/backend/requirements.txt" -q

    cat > "${PROJECT_DIR}/start.sh" << 'STARTEOF'
#!/usr/bin/env bash
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
cd "$SCRIPT_DIR"
IP=$(hostname -I 2>/dev/null | awk '{print $1}' || echo "localhost")
echo ""
echo "============================================================"
echo "              WinBox Web is starting..."
echo "============================================================"
echo ""
echo "  Web UI:    http://$IP:8080"
echo "  noVNC:     http://$IP:6080"
echo ""
echo "  Press Ctrl+C to stop"
echo "============================================================"
echo ""
exec "$SCRIPT_DIR/venv/bin/python" "$SCRIPT_DIR/backend/main.py"
STARTEOF
    chmod +x "${PROJECT_DIR}/start.sh"

    _ok "Installation complete!"
}

do_start() {
    if [[ ! -d "$VENV_DIR" ]]; then
        _fail "Not installed yet. Run: ./winbox-web.sh (no args to auto-install)"
        exit 1
    fi
    cd "$PROJECT_DIR"
    IP=$(hostname -I 2>/dev/null | awk '{print $1}' || echo "localhost")
    echo ""
    echo -e "${C}══════════════════════════════════════════════════════════════${W}"
    echo -e "${C}              WinBox Web is starting...${W}"
    echo -e "${C}══════════════════════════════════════════════════════════════${W}"
    echo ""
    echo -e "  ${G}🌐 Web UI:${W}    http://${IP}:8080"
    echo -e "  ${G}🔌 noVNC:${W}     http://${IP}:6080"
    echo ""
    echo -e "  ${Y}Press Ctrl+C to stop${W}"
    echo -e "${C}══════════════════════════════════════════════════════════════${W}"
    echo ""
    exec "$VENV_DIR/bin/python" "$PROJECT_DIR/backend/main.py"
}

case "${1:-}" in
    --install) do_install ;;
    --start) do_start ;;
    --help|-h)
        echo "Usage: ./winbox-web.sh [OPTION]"
        echo ""
        echo "  (no args)      Auto-install if needed, then start"
        echo "  --install      Install only"
        echo "  --start        Start server (after install)"
        echo ""
        echo "Env vars: WINBOX_WEB_PORT, WINBOX_WS_PORT, WINBOX_VNC_PORT"
        exit 0
        ;;
    *)
        if [[ ! -d "$VENV_DIR" ]]; then do_install; fi
        do_start
        ;;
esac
